from flask import Flask, request, jsonify
from itsdangerous import URLSafeTimedSerializer

app = Flask(__name__)
SECRET_KEY = 'your_secret_key'  # Change this to a secure random key in production
serializer = URLSafeTimedSerializer(SECRET_KEY)

# In-memory user database for demonstration purposes
users = {
    "user1": "password1",
    "user2": "password2"
}

def generate_token(username):
    return serializer.dumps(username, salt='login-salt')

def verify_token(token):
    try:
        username = serializer.loads(token, salt='login-salt', max_age=3600)  # Token expires in one hour
        return username
    except Exception:
        return None

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')

    if username in users and users[username] == password:
        token = generate_token(username)
        return jsonify({"token": token}), 200
    else:
        return jsonify({"message": "Invalid credentials"}), 401

@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')

    if not token:
        return jsonify({"message": "Token is missing"}), 401

    username = verify_token(token)

    if not username:
        return jsonify({"message": "Invalid token"}), 401

    return jsonify({"message": f"Hello, {username}!"}), 200

if __name__ == '__main__':
    app.run(debug=True)